"""Mechanical code generation: project spec → buildable PlatformIO tree.

Pure templating. No LLM, no regex post-processing. Each module declares three
Jinja2 fragments (``globals``, ``setup``, ``loop``) plus driver source files;
this generator stitches them into a single ``main.cpp`` and copies the driver
files into ``lib/atech_<module>/``.
"""

from __future__ import annotations

from pathlib import Path
from typing import TYPE_CHECKING

from jinja2 import Environment, StrictUndefined

from atech.catalog import iter_module_files
from atech.catalog.models import BoardSpec, ModuleSpec

if TYPE_CHECKING:
    from atech.project import Project, ProjectModule

# Jinja env shared by every module template. StrictUndefined catches typos in
# module manifests early (e.g. {{ pinA }} instead of {{ pin_a }}).
_JINJA = Environment(
    undefined=StrictUndefined,
    keep_trailing_newline=True,
    trim_blocks=False,
    lstrip_blocks=False,
)

_MAIN_CPP_TEMPLATE = """\
// Generated by atech-sdk. Do not edit by hand — re-run `atech build` instead.
//
// Project: {{ project.name }}
// Board:   {{ board.name }} ({{ board.id }})
{%- for m in project.modules %}
// Module:  {{ m.module_id }} as {{ m.instance }} on {{ m.ports | join(', ') }}
{%- endfor %}

#include <Arduino.h>
#include "esp_system.h"   // esp_reset_reason() for boot diagnostics
{%- for include in includes %}
#include "{{ include }}"
{%- endfor %}

{% for block in globals_blocks %}
{{ block }}
{%- endfor %}

void setup() {
    Serial.begin(115200);
    Serial.setTxTimeoutMs(0);    // Don't block when no host is listening
{%- for block in setup_blocks %}

    {{ block | indent(4) }}
{%- endfor %}
{%- if user_setup %}

    // ---- user setup ----
    {{ user_setup | indent(4) }}
{%- endif %}

    // ---- atech boot diagnostics (read by `atech check`) ----
    {{ diagnostics_block | indent(4) }}
}

void loop() {
{%- for block in loop_blocks %}
    {{ block | indent(4) }}
{%- endfor %}
{%- if user_loop %}

    // ---- user loop ----
    {{ user_loop | indent(4) }}
{%- endif %}
}
"""


_PLATFORMIO_INI = """\
; Generated by atech-sdk. Re-run `atech build` to refresh.
[env:{{ env }}]
platform = espressif32
board = {{ env }}
framework = {{ framework }}
monitor_speed = 115200
; 460800 (not 921600) + explicit reset flags make flashing reliable over the
; ESP32-S3 native USB-CDC, which otherwise often hangs at "Connecting...".
upload_speed = 460800
upload_flags =
    --before=default_reset
    --after=hard_reset
; ARDUINO_USB_MODE=1 + CDC_ON_BOOT=1 route `Serial` to the native USB-CDC class on
; ESP32-S3, which is what the host-side `atech.runtime.Board` listens to. It also
; gives Serial a setTxTimeoutMs(...) method so firmware can run untethered without
; blocking when no host is reading.
build_flags =
    -DCORE_DEBUG_LEVEL=0
    -DARDUINO_USB_MODE=1
    -DARDUINO_USB_CDC_ON_BOOT=1
{%- if lib_deps %}
lib_deps =
{%- for dep in lib_deps %}
    {{ dep }}
{%- endfor %}
{%- endif %}
"""


def _render(template_text: str, context: dict) -> str:
    return _JINJA.from_string(template_text).render(**context)


def _port_gpios(board: BoardSpec, port_id: str) -> tuple[int, int]:
    """(Line A, Line B) GPIOs for a port; 0 for an absent line."""
    p = board.port(port_id)
    a = p.pins[0].gpio if p.pins else 0
    b = p.pins[1].gpio if len(p.pins) > 1 else 0
    return a, b


def _module_context(
    project_module: "ProjectModule",
    board: BoardSpec,
    spec: ModuleSpec,
) -> dict:
    """Variables every module template can reference.

    Single-width modules use the one port's Line A/B as pin_a/pin_b.

    Double-width modules span two adjacent ports. Pin assignment mirrors the
    firmware/backend ``resolve_double_module_pins`` rule (the single source of
    truth): the *lower-numbered* port is primary, and **on the left side of the
    board the two port groups are swapped** — pin_a/pin_b come from the
    secondary (higher) port and pin_a2/pin_b2 from the primary — because a module
    snaps into the left column rotated 180° vs the right. This makes orientation
    automatic from the board geometry, so the order the user writes the ports in
    doesn't matter.
    """
    ctx: dict = {
        "instance": project_module.instance,
        "module_id": project_module.module_id,
        "class_name": spec.driver.class_name,
    }

    ports = list(project_module.ports)
    if len(ports) == 1:
        pin_a, pin_b = _port_gpios(board, ports[0])
        ctx.update(port_id=ports[0], pin_a=pin_a, pin_b=pin_b)
        return ctx

    # Double-width: primary = lower-numbered port; secondary = higher.
    lower, higher = sorted(ports, key=lambda pid: board.port(pid).slot_number or 0)
    primary_side = (board.port(lower).side or "right").lower()
    lo_a, lo_b = _port_gpios(board, lower)
    hi_a, hi_b = _port_gpios(board, higher)

    if primary_side == "left":
        # Left column is mirrored: secondary (higher) port supplies pin_a/pin_b.
        (pa, pb, pid1), (pa2, pb2, pid2) = (hi_a, hi_b, higher), (lo_a, lo_b, lower)
    else:
        (pa, pb, pid1), (pa2, pb2, pid2) = (lo_a, lo_b, lower), (hi_a, hi_b, higher)

    ctx.update(
        port_id=pid1, pin_a=pa, pin_b=pb,
        port_id_2=pid2, pin_a2=pa2, pin_b2=pb2,
    )
    return ctx


# --------------------------------------------------------- boot diagnostics

_RESET_REASON_SWITCH = """\
esp_reset_reason_t _rr = esp_reset_reason();
const char* _rrs;
switch (_rr) {
    case ESP_RST_POWERON:   _rrs = "POWERON";   break;
    case ESP_RST_EXT:       _rrs = "EXT";       break;
    case ESP_RST_SW:        _rrs = "SOFTWARE";  break;
    case ESP_RST_PANIC:     _rrs = "PANIC";     break;
    case ESP_RST_INT_WDT:   _rrs = "INT_WDT";   break;
    case ESP_RST_TASK_WDT:  _rrs = "TASK_WDT";  break;
    case ESP_RST_WDT:       _rrs = "WDT";       break;
    case ESP_RST_BROWNOUT:  _rrs = "BROWNOUT";  break;
    case ESP_RST_DEEPSLEEP: _rrs = "DEEPSLEEP"; break;
    default:                _rrs = "UNKNOWN";   break;
}
"""


def render_diagnostics(project: "Project", board: BoardSpec, specs: dict) -> str:
    """C++ that prints a one-line JSON boot report: reset reason, heap, modules.

    Wire shape (read by ``atech check`` / ``Board.diagnostics()``):
      {"type":"boot","payload":{"reset_reason":"POWERON","free_heap":N,
        "modules":[{"instance":"th","module":"aht20","ok":true,"detectable":true}]}}
    """
    lines: list[str] = ["{"]
    lines.append(_RESET_REASON_SWITCH.rstrip())
    lines.append('Serial.print("{\\"type\\":\\"boot\\",\\"payload\\":{\\"reset_reason\\":\\"");')
    lines.append("Serial.print(_rrs);")
    lines.append('Serial.print("\\",\\"free_heap\\":");')
    lines.append("Serial.print((unsigned)ESP.getFreeHeap());")
    lines.append('Serial.print(",\\"modules\\":[");')

    for idx, pm in enumerate(project.modules):
        spec = specs[pm.module_id]
        ctx = _module_context(pm, board, spec)
        sep = "" if idx == 0 else ","
        prefix = (
            f'{{\\"instance\\":\\"{pm.instance}\\",'
            f'\\"module\\":\\"{pm.module_id}\\",\\"ok\\":'
        )
        lines.append(f'Serial.print("{sep}{prefix}");')
        if spec.health_check:
            expr = _render(spec.health_check, ctx).strip()
            lines.append(f'Serial.print(({expr}) ? "true" : "false");')
            lines.append('Serial.print(",\\"detectable\\":true}");')
        else:
            # No read-back: report initialized, but presence can't be verified.
            lines.append('Serial.print("true");')
            lines.append('Serial.print(",\\"detectable\\":false}");')

    lines.append('Serial.println("]}}");')
    lines.append("}")
    return "\n".join(lines)


# --------------------------------------------------------------- file emit


def render_main_cpp(project: "Project") -> str:
    board = project.board_spec
    specs = project.module_specs()

    includes: list[str] = []
    globals_blocks: list[str] = []
    setup_blocks: list[str] = []
    loop_blocks: list[str] = []

    seen_includes: set[str] = set()
    for pm in project.modules:
        spec = specs[pm.module_id]
        ctx = _module_context(pm, board, spec)

        header = spec.driver.header
        if header not in seen_includes:
            includes.append(header)
            seen_includes.add(header)

        if spec.templates.globals:
            globals_blocks.append(_render(spec.templates.globals, ctx).rstrip())
        if spec.templates.setup:
            setup_blocks.append(_render(spec.templates.setup, ctx).strip())
        if spec.templates.loop:
            loop_blocks.append(_render(spec.templates.loop, ctx).strip())

    main_ctx = {
        "project": project,
        "board": board,
        "includes": includes,
        "globals_blocks": globals_blocks,
        "setup_blocks": setup_blocks,
        "loop_blocks": loop_blocks,
        "user_setup": (project.setup_code or "").strip(),
        "user_loop": (project.loop_code or "").strip(),
        "diagnostics_block": render_diagnostics(project, board, specs),
    }
    return _render(_MAIN_CPP_TEMPLATE, main_ctx)


def render_platformio_ini(project: "Project") -> str:
    board = project.board_spec
    deps: list[str] = []
    seen: set[str] = set()
    for spec in project.module_specs().values():
        for dep in spec.lib_deps:
            if dep not in seen:
                deps.append(dep)
                seen.add(dep)
    ctx = {
        "env": board.platformio_env,
        "framework": board.platformio_framework,
        "lib_deps": deps,
    }
    return _render(_PLATFORMIO_INI, ctx)


def render_project_readme(project: "Project") -> str:
    board = project.board_spec
    specs = project.module_specs()
    lines: list[str] = []
    lines.append(f"# {project.name}")
    lines.append("")
    lines.append(f"Generated firmware for **{board.name}** (`{board.id}`).")
    lines.append("")
    lines.append("## Modules")
    lines.append("")
    for pm in project.modules:
        spec = specs[pm.module_id]
        ports = ", ".join(pm.ports)
        lines.append(f"- **{spec.name}** (`{pm.module_id}`) as `{pm.instance}` on `{ports}`")
    lines.append("")
    lines.append("## Build & flash")
    lines.append("")
    lines.append("```bash")
    lines.append("pio run                         # build")
    lines.append("pio run -t upload               # flash")
    lines.append("```")
    lines.append("")
    lines.append("Or from Python via the Atech SDK:")
    lines.append("")
    lines.append("```python")
    lines.append("from atech import Project")
    lines.append("Project.load('project.yaml').upload()")
    lines.append("```")
    lines.append("")
    return "\n".join(lines)


def generate_project(project: "Project", out_dir: Path) -> Path:
    """Write a complete PlatformIO project to ``out_dir`` and return the path."""
    project.ensure_valid()

    out_dir.mkdir(parents=True, exist_ok=True)
    src_dir = out_dir / "src"
    src_dir.mkdir(exist_ok=True)
    lib_dir = out_dir / "lib"
    lib_dir.mkdir(exist_ok=True)

    # platformio.ini
    (out_dir / "platformio.ini").write_text(render_platformio_ini(project), encoding="utf-8")

    # main.cpp
    (src_dir / "main.cpp").write_text(render_main_cpp(project), encoding="utf-8")

    # Drivers: one library per unique module (deduped by id). External
    # modules (Project.use_modules_from / modules_path) win over bundled.
    extras = list(project.extra_module_paths)
    seen: set[str] = set()
    for pm in project.modules:
        if pm.module_id in seen:
            continue
        seen.add(pm.module_id)
        module_lib = lib_dir / f"atech_{pm.module_id}"
        module_lib.mkdir(exist_ok=True)
        for filename, blob in iter_module_files(pm.module_id, extra_paths=extras):
            if filename == "module.yaml":
                continue
            (module_lib / filename).write_bytes(blob)

    # Per-project README + the project.yaml round-trip
    (out_dir / "README.md").write_text(render_project_readme(project), encoding="utf-8")
    (out_dir / "project.yaml").write_text(project.to_yaml(), encoding="utf-8")

    return out_dir
